from collections import defaultdict
from typing import List

class Solution:
	def solve(self, nums: List[int]) -> bool:
		lengths = defaultdict(int)
		for i in range(len(nums)):
			start = i
			while start < len(nums):
				length = start - i + 1
				lengths[length] += 1
				start += length
				if lengths[length] > 1:
					return [nums[i:i+length]]
		return []

