template <typename T>
vector<T> readVector() {
	vector<T> vec;
	int n;
	cin >> n;
	for (int i = 0; i < n; i++) {
		T num;
		cin >> num;
		vec.push_back(num);
	}
	return vec;
}

bool Solution::solve(vector<int>& nums) {
	unordered_map<int, int> lengths;
	for (int i = 0; i < nums.size(); i++) {
		int start = i;
		while (start < nums.size()) {
			int length = start - i + 1;
			lengths[length]++;
			start += length;
			if (lengths[length] > 1) return true;
		}
	}
	return false;
}
